UPDATE videos
SET view_count = view_count + 1
WHERE id = #{videoId}

UPDATE videos
SET like_count = like_count + 1
WHERE id = #{videoId}

mapper.select:
SELECT v.*, vc.name as category_name, u.real_name as audit_admin_name FROM videos v LEFT JOIN video_categories vc ON v.category_id = vc.id LEFT JOIN users u ON v.audit_admin_id = u.id WHERE 1=1
AND v.status = #{status}
AND v.uploader_type = #{uploaderType}
AND (v.title LIKE CONCAT('%', #{keyword}, '%') OR v.uploader_name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY v.created_at DESC

